@namespace sv_c0ceed881e9d49f69d32354483907722.Components.Pages.Settings

<section class="settings-section">
    <h3>Profile</h3>

    <div class="profile-layout">
        <div class="avatar-area">
            <div class="avatar-preview">
                @if (!string.IsNullOrWhiteSpace(AvatarUrl))
                {
                    <img src="@AvatarUrl" alt="Avatar" />
                }
                else
                {
                    <span class="avatar-placeholder">👤</span>
                }
            </div>
            <label class="form-label mt-2">Avatar URL</label>
            <input type="url" class="form-control form-control-sm" value="@AvatarUrl"
                   @onchange="e => AvatarUrl = e.Value?.ToString() ?? string.Empty" />
        </div>

        <div class="profile-fields">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="DisplayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="Email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="Bio"></textarea>
            </div>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(_statusMessage))
    {
        <div class="alert @(_isError ? "alert-danger" : "alert-success") mt-3 alert-dismissible" role="alert">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <div class="mt-3 d-flex gap-2">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@_saving">
            Discard Changes
        </button>
    </div>
</section>

@code {
    [Parameter, EditorRequired]
    public UserProfile? Profile { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName = "";
    private string Email = "";
    private string AvatarUrl = "";
    private string Bio = "";

    private string? _statusMessage;
    private bool _isError;
    private bool _saving;

    // Snapshot of last-saved state for discard
    private UserProfile? _savedSnapshot;

    protected override void OnParametersSet()
    {
        if (Profile is not null && _savedSnapshot is null)
        {
            _savedSnapshot = Profile;
            ApplyProfile(Profile);
        }
    }

    private void ApplyProfile(UserProfile p)
    {
        DisplayName = p.DisplayName;
        Email = p.Email;
        AvatarUrl = p.AvatarUrl;
        Bio = p.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
            await OnSave.InvokeAsync(updated);
            _savedSnapshot = updated;
            _statusMessage = "Profile saved successfully!";
            _isError = false;
        }
        catch
        {
            _statusMessage = "Failed to save profile. Please try again.";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        if (_savedSnapshot is not null)
        {
            ApplyProfile(_savedSnapshot);
        }
        _statusMessage = null;
    }
}

.settings-section h3 {
    margin-bottom: 1.5rem;
    font-weight: 600;
    font-size: 1.3rem;
}

.profile-layout {
    display: flex;
    gap: 2rem;
}

.avatar-area {
    flex: 0 0 160px;
    text-align: center;
}

.avatar-preview {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    overflow: hidden;
    background: #e9ecef;
    display: flex;
    align-items: center;
    justify-content: center;
    margin: 0 auto 0.75rem;
    border: 3px solid #dee2e6;
}

.avatar-preview img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    font-size: 3rem;
}

.profile-fields {
    flex: 1;
}

@namespace sv_c0ceed881e9d49f69d32354483907722.Components.Pages.Settings

<section class="settings-section">
    <h3>Notifications</h3>

    <div class="mb-4">
        <h6>General</h6>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="emailNotif"
                   checked="@EmailNotifications"
                   @onchange="e => EmailNotifications = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="pushNotif"
                   checked="@PushNotifications"
                   @onchange="e => PushNotifications = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="weeklyDigest"
                   checked="@WeeklyDigest"
                   @onchange="e => WeeklyDigest = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <div class="mb-4">
        <h6>Muted Channels</h6>
        @if (AvailableChannels.Count > 0)
        {
            <div class="channel-list">
                @foreach (var channel in AvailableChannels)
                {
                    var isMuted = MutedChannels.Contains(channel);
                    <div class="form-check mb-1">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                               checked="@isMuted"
                               @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="@($"ch-{channel}")">@channel (muted)</label>
                    </div>
                }
            </div>
        }
        else
        {
            <p class="text-muted">No channels available.</p>
        }
    </div>

    @if (!string.IsNullOrEmpty(_statusMessage))
    {
        <div class="alert alert-success alert-dismissible" role="alert">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
        @if (_saving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Preferences
    </button>
</section>

@code {
    [Parameter, EditorRequired]
    public NotificationPrefs? Prefs { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<NotificationPrefs> OnSave { get; set; }

    [Parameter]
    public List<string> AvailableChannels { get; set; } = ["general", "announcements", "updates", "marketing", "alerts"];

    private bool EmailNotifications;
    private bool PushNotifications;
    private bool WeeklyDigest;
    private List<string> MutedChannels = [];

    private string? _statusMessage;
    private bool _saving;
    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !_initialized)
        {
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            MutedChannels = [.. Prefs.MutedChannels];
            _initialized = true;
        }
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted && !MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
        else if (!muted)
            MutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, [.. MutedChannels]);
            await OnSave.InvokeAsync(updated);
            _statusMessage = "Notification preferences saved!";
        }
        finally
        {
            _saving = false;
        }
    }
}

.channel-list {
    max-height: 200px;
    overflow-y: auto;
    padding: 0.5rem;
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    background: #fff;
}

