+    private bool _saving;
+
+    // Snapshot of last-saved state for discard
+    private UserProfile? _savedSnapshot;
+
+    protected override void OnParametersSet()
+    {
+        if (Profile is not null && _savedSnapshot is null)
+        {
+            _savedSnapshot = Profile;
+            ApplyProfile(Profile);
+        }
+    }
+
+    private void ApplyProfile(UserProfile p)
+    {
+        DisplayName = p.DisplayName;
+        Email = p.Email;
+        AvatarUrl = p.AvatarUrl;
+        Bio = p.Bio;
+    }
+
+    private async Task SaveAsync()
+    {
+        _saving = true;
+        _statusMessage = null;
+        try
+        {
+            var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
+            await OnSave.InvokeAsync(updated);
+            _savedSnapshot = updated;
+            _statusMessage = "Profile saved successfully!";
+            _isError = false;
+        }
+        catch
+        {
+            _statusMessage = "Failed to save profile. Please try again.";
+            _isError = true;
+        }
+        finally
+        {
+            _saving = false;
+        }
+    }
+
+    private void Discard()
+    {
+        if (_savedSnapshot is not null)
+        {
+            ApplyProfile(_savedSnapshot);
+        }
+        _statusMessage = null;
+    }
+}
+

