@code {
    [Parameter]
    public AppearanceSettings? Settings { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string Theme = "Light";
    private string FontSize = "Medium";
    private string Language = "English";
    private bool CompactMode;

    private string? _statusMessage;
    private bool _saving;
    private bool _initialized;

    private static readonly string[] Languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese", "Korean"];

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_initialized)
        {
            Theme = Settings.Theme;
            FontSize = Settings.FontSize;
            Language = Settings.Language;
            CompactMode = Settings.CompactMode;
            _initialized = true;
        }
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var updated = new AppearanceSettings(Theme, FontSize, Language, CompactMode);
            await OnSave.InvokeAsync(updated);
            _statusMessage = "Appearance settings saved!";
        }
        finally
        {
            _saving = false;
        }
    }

    private string GetPreviewThemeClass() => Theme switch
    {
        "Dark" => "preview-dark",
        _ => "preview-light"
    };

    private string GetPreviewFontSize() => FontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };
}

.preview-area {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    transition: all 0.2s;
}

.preview-light {
    background: #fff;
    color: #212529;
}

.preview-dark {
    background: #1e1e2e;
    color: #e0e0e0;
}

.preview-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid rgba(128, 128, 128, 0.2);
}

.preview-light .preview-header {
    background: #f8f9fa;
}

.preview-dark .preview-header {
    background: #2a2a3e;
}

.preview-body {
    padding: 1rem;
}

.preview-body.compact {
    padding: 0.5rem 1rem;
    line-height: 1.3;
}

.preview-body.compact p {
    margin-bottom: 0.25rem;
}

.preview-meta {
    font-size: 0.85em;
    opacity: 0.7;
}

.preview-card {
    padding: 0.75rem;
    border-radius: 0.375rem;
    margin-top: 0.5rem;
}

.preview-light .preview-card {
    background: #e9ecef;
    border: 1px solid #dee2e6;
}

.preview-dark .preview-card {
    background: #343450;
    border: 1px solid #444;
}

